import React, { useState, useEffect } from 'react';
import styled from 'styled-components';
import { motion } from 'framer-motion';
import { 
  subscribeToMetalsUpdates, 
  MetalsData, 
  ChartData,
  calculateIndicators
} from '../services/metalsApi';
import { getStaticHistoricalData } from '../services/staticHistoricalData';
import CorrelationChart from '../components/CorrelationChart';
import PriceTrendChart from '../components/PriceTrendChart';
import MetalsPredictionChart from '../components/MetalsPredictionChart';
import MonthlyPredictionTable from '../components/MonthlyPredictionTable';

const GoldSilverContainer = styled.div`
  max-width: 1400px;
  margin: 0 auto;
  padding: 1rem 0;
`;

const PageHeader = styled(motion.div)`
  margin-bottom: 4rem;

  h1 {
    font-size: 3.5rem;
    font-weight: 900;
    letter-spacing: -2px;
    margin-bottom: 1rem;
    background: ${props => props.theme.colors.accentPrimary};
    -webkit-background-clip: text;
    -webkit-text-fill-color: transparent;
  }

  p {
    color: ${props => props.theme.colors.textSecondary};
    font-size: 1.1rem;
    max-width: 600px;
  }
`;

const GlassCard = styled(motion.div)`
  background: ${props => props.theme.colors.cardBackground};
  border-radius: ${props => props.theme.borderRadius.large};
  border: 1px solid ${props => props.theme.colors.border};
  backdrop-filter: blur(12px);
  box-shadow: ${props => props.theme.shadows.card};
  position: relative;
  overflow: hidden;
`;

const LiveSection = styled.div`
  display: grid;
  grid-template-columns: repeat(2, 1fr);
  gap: 2rem;
  margin-bottom: 4rem;

  @media (max-width: 1024px) {
    grid-template-columns: 1fr;
  }
`;

const MetalCard = styled(GlassCard)<{ positive: boolean }>`
  padding: 4rem;
  display: flex;
  flex-direction: column;
  align-items: center;
  text-align: center;

  &::after {
    content: '';
    position: absolute;
    top: 0;
    right: 0;
    width: 200px;
    height: 200px;
    background: radial-gradient(circle, ${props => props.positive ? props.theme.colors.success : props.theme.colors.danger}08 0%, transparent 70%);
    z-index: -1;
  }
`;

const MetalIcon = styled.div`
  font-size: 4rem;
  margin-bottom: 1.5rem;
  filter: drop-shadow(0 0 15px rgba(255, 255, 255, 0.1));
`;

const MetalName = styled.h2`
  font-size: 1rem;
  color: ${props => props.theme.colors.textSecondary};
  margin-bottom: 1.5rem;
  text-transform: uppercase;
  letter-spacing: 4px;
  font-weight: 700;
`;

const PriceText = styled.div`
  font-size: 5rem;
  font-weight: 900;
  color: ${props => props.theme.colors.textPrimary};
  margin-bottom: 1rem;
  letter-spacing: -3px;
  font-family: 'JetBrains Mono', monospace;
`;

const PriceChange = styled.div<{ positive: boolean }>`
  font-size: 1.5rem;
  font-weight: 700;
  color: ${props => props.positive ? props.theme.colors.success : props.theme.colors.danger};
  display: inline-flex;
  align-items: center;
  gap: 0.8rem;
  padding: 0.5rem 1.2rem;
  background: ${props => props.positive ? props.theme.colors.success : props.theme.colors.danger}15;
  border-radius: 12px;
  margin-bottom: 2rem;
`;

const AnalyticsGrid = styled.div`
  display: grid;
  grid-template-columns: 1.5fr 1fr;
  gap: 2rem;
  margin-bottom: 4rem;

  @media (max-width: 1024px) {
    grid-template-columns: 1fr;
  }
`;

const PredictionTableContainer = styled(GlassCard)`
  padding: 3rem;
  margin-bottom: 4rem;
`;

const TableTitle = styled.h2`
  font-size: 1.8rem;
  color: ${props => props.theme.colors.textPrimary};
  margin-bottom: 2.5rem;
  font-weight: 800;
  letter-spacing: -0.5px;
  display: flex;
  justify-content: space-between;
  align-items: center;
`;

const StyledTable = styled.table`
  width: 100%;
  border-collapse: separate;
  border-spacing: 0 12px;

  th {
    padding: 1rem 1.5rem;
    text-align: left;
    color: ${props => props.theme.colors.textSecondary};
    text-transform: uppercase;
    font-size: 0.75rem;
    letter-spacing: 1.5px;
    font-weight: 700;
  }

  td {
    padding: 1.5rem;
    font-size: 1.1rem;
    font-weight: 600;
    color: ${props => props.theme.colors.textPrimary};
    background: ${props => props.theme.colors.glass};

    &:first-child {
      border-radius: 12px 0 0 12px;
      border-left: 1px solid ${props => props.theme.colors.border};
    }

    &:last-child {
      border-radius: 0 12px 12px 0;
      border-right: 1px solid ${props => props.theme.colors.border};
    }

    border-top: 1px solid ${props => props.theme.colors.border};
    border-bottom: 1px solid ${props => props.theme.colors.border};
  }

  tr:hover td {
    background: rgba(255, 255, 255, 0.05);
    border-color: ${props => props.theme.colors.info}30;
  }
`;

const SentimentSection = styled.div`
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 2rem;
  margin-bottom: 4rem;

  @media (max-width: 1024px) {
    grid-template-columns: 1fr;
  }
`;

const SentimentCard = styled(GlassCard)<{ sentiment: 'bullish' | 'bearish' | 'neutral' }>`
  padding: 2.5rem;

  .label {
    font-size: 0.75rem;
    text-transform: uppercase;
    letter-spacing: 1.5px;
    color: ${props => props.theme.colors.textSecondary};
    font-weight: 700;
    margin-bottom: 1rem;
  }

  .value {
    font-size: 2.5rem;
    font-weight: 900;
    margin-bottom: 1rem;
    color: ${props => {
      if (props.sentiment === 'bullish') return props.theme.colors.success;
      if (props.sentiment === 'bearish') return props.theme.colors.danger;
      return props.theme.colors.warning;
    }};
  }

  .description {
    font-size: 0.95rem;
    color: ${props => props.theme.colors.textSecondary};
    line-height: 1.6;
  }
`;

const GoldSilver: React.FC = () => {
  const [metalsData, setMetalsData] = useState<MetalsData | null>(null);
  const [chartData, setChartData] = useState<ChartData | null>(null);
  const [loading, setLoading] = useState(true);
  const [lastUpdate, setLastUpdate] = useState<Date>(new Date());

  useEffect(() => {
    const unsubscribe = subscribeToMetalsUpdates(
      (data) => {
        setMetalsData(data);
        setLoading(false);
        setLastUpdate(new Date());
      },
      30000
    );

    const loadCharts = () => {
      const data = getStaticHistoricalData();
      data.goldHistory = calculateIndicators(data.goldHistory);
      data.silverHistory = calculateIndicators(data.silverHistory);
      setChartData(data);
    };

    loadCharts();
    return unsubscribe;
  }, []);

  const formatCurrency = (val: number, decimals: number = 2) => {
    return new Intl.NumberFormat('en-US', {
      style: 'currency',
      currency: 'USD',
      minimumFractionDigits: decimals,
      maximumFractionDigits: decimals
    }).format(val);
  };

  const getPredictionData = (history: any[]) => {
    if (!history || history.length < 5) return { price: 0, change: 0, direction: 'up' };
    const last = history[history.length - 1].price;
    const prev = history[history.length - 5].price;
    const predicted = last + (last - prev) / 2;
    return {
      price: predicted,
      change: ((predicted - last) / last) * 100,
      direction: predicted >= last ? 'up' : 'down'
    };
  };

  const goldPred = getPredictionData(chartData?.goldHistory || []);
  const silverPred = getPredictionData(chartData?.silverHistory || []);

  return (
    <GoldSilverContainer>
      <PageHeader
        initial={{ opacity: 0, y: 20 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ duration: 0.8 }}
      >
        <h1>Commodity Intelligence</h1>
        <p>Real-time precious metals tracking and advanced predictive analytics powered by Zeus's market engine.</p>
      </PageHeader>

      <LiveSection>
        {loading ? (
          <GlassCard style={{ padding: '4rem', gridColumn: 'span 2', textAlign: 'center' }}>
            <div style={{ fontSize: '2rem', marginBottom: '1rem' }}>📡</div>
            <p style={{ color: '#94a3b8' }}>Establishing secure connection to market data feeds...</p>
          </GlassCard>
        ) : metalsData && (
          <>
            <MetalCard 
              positive={metalsData.gold.change >= 0}
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ delay: 0.2 }}
            >
              <div style={{ position: 'absolute', top: '2rem', left: '2rem', display: 'flex', alignItems: 'center', gap: '8px', color: '#ef4444', fontSize: '0.8rem', fontWeight: 800 }}>
                <motion.div 
                  animate={{ scale: [1, 1.2, 1] }} 
                  transition={{ duration: 2, repeat: Infinity }}
                  style={{ width: '8px', height: '8px', background: '#ef4444', borderRadius: '50%' }}
                />
                LIVE
              </div>
              <MetalIcon>💰</MetalIcon>
              <MetalName>Gold Spot (XAU/USD)</MetalName>
              <PriceText>{formatCurrency(metalsData.gold.price)}</PriceText>
              <PriceChange positive={metalsData.gold.change >= 0}>
                {metalsData.gold.change >= 0 ? '▲' : '▼'} 
                {Math.abs(metalsData.gold.changePercent).toFixed(2)}%
              </PriceChange>
              <div style={{ color: '#94a3b8', fontSize: '0.8rem', fontWeight: 500 }}>
                Last updated at {lastUpdate.toLocaleTimeString()}
              </div>
            </MetalCard>

            <MetalCard 
              positive={metalsData.silver.change >= 0}
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ delay: 0.3 }}
            >
              <div style={{ position: 'absolute', top: '2rem', left: '2rem', display: 'flex', alignItems: 'center', gap: '8px', color: '#ef4444', fontSize: '0.8rem', fontWeight: 800 }}>
                <motion.div 
                  animate={{ scale: [1, 1.2, 1] }} 
                  transition={{ duration: 2, repeat: Infinity }}
                  style={{ width: '8px', height: '8px', background: '#ef4444', borderRadius: '50%' }}
                />
                LIVE
              </div>
              <MetalIcon>🥈</MetalIcon>
              <MetalName>Silver Spot (XAG/USD)</MetalName>
              <PriceText>{formatCurrency(metalsData.silver.price, 4)}</PriceText>
              <PriceChange positive={metalsData.silver.change >= 0}>
                {metalsData.silver.change >= 0 ? '▲' : '▼'} 
                {Math.abs(metalsData.silver.changePercent).toFixed(2)}%
              </PriceChange>
              <div style={{ color: '#94a3b8', fontSize: '0.8rem', fontWeight: 500 }}>
                Last updated at {lastUpdate.toLocaleTimeString()}
              </div>
            </MetalCard>
          </>
        )}
      </LiveSection>

      <SentimentSection>
        <SentimentCard sentiment="bullish">
          <div className="label">Gold Sentiment</div>
          <div className="value">Strong Bullish</div>
          <p className="description">
            Institutional accumulation continues as macro-economic indicators suggest sustained demand. Technical oscillators show strong momentum with support levels holding firmly.
          </p>
          <div style={{ marginTop: '2rem', display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '1rem' }}>
            <div style={{ background: 'rgba(255,255,255,0.03)', padding: '1rem', borderRadius: '12px', border: '1px solid rgba(255,255,255,0.05)' }}>
              <div style={{ fontSize: '0.7rem', color: '#94a3b8', marginBottom: '4px' }}>AI Rating</div>
              <div style={{ fontSize: '1.1rem', fontWeight: 800, color: '#10b981' }}>92/100</div>
            </div>
            <div style={{ background: 'rgba(255,255,255,0.03)', padding: '1rem', borderRadius: '12px', border: '1px solid rgba(255,255,255,0.05)' }}>
              <div style={{ fontSize: '0.7rem', color: '#94a3b8', marginBottom: '4px' }}>Volatility</div>
              <div style={{ fontSize: '1.1rem', fontWeight: 800 }}>Low</div>
            </div>
          </div>
        </SentimentCard>

        <SentimentCard sentiment="neutral">
          <div className="label">Silver Sentiment</div>
          <div className="value">Neutral-Positive</div>
          <p className="description">
            Industrial demand remains stable while speculative flows show signs of consolidation. Market awaits key manufacturing PMI data for the next directional move.
          </p>
          <div style={{ marginTop: '2rem', display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '1rem' }}>
            <div style={{ background: 'rgba(255,255,255,0.03)', padding: '1rem', borderRadius: '12px', border: '1px solid rgba(255,255,255,0.05)' }}>
              <div style={{ fontSize: '0.7rem', color: '#94a3b8', marginBottom: '4px' }}>AI Rating</div>
              <div style={{ fontSize: '1.1rem', fontWeight: 800, color: '#f59e0b' }}>68/100</div>
            </div>
            <div style={{ background: 'rgba(255,255,255,0.03)', padding: '1rem', borderRadius: '12px', border: '1px solid rgba(255,255,255,0.05)' }}>
              <div style={{ fontSize: '0.7rem', color: '#94a3b8', marginBottom: '4px' }}>Volatility</div>
